arguments.command:
for n in Clover mCherry TagRFP mKO2 "Kusabira Orange" PSmOrange Dendra2 HcRed "Azami Green" muGFP Gamillus; do
  echo "=== $n ==="
  curl -s --max-time 20 "https://www.fpbase.org/api/proteins/?name__icontains=$(python3 -c "import urllib.parse,sys;print(urllib.parse.quote('$n'))")&format=json" | python3 -c "import sys,json;
d=json.load(sys.stdin)
for p in d:
  st=p.get('states',[])
  for s in st:
    print(p['name'],'ex',s.get('ex_max'),'em',s.get('em_max'))" 2>/dev/null
done

